#!/usr/bin/env node
/**
 * Upload every remaining TXT novel from data/全部完结短篇小说合集.
 *
 * The script is intentionally resumable:
 * - Before each batch it scans local DB / production admin API.
 * - Already uploaded titles are skipped.
 * - Covers are generated by the xsread-novel-uploader skill through gpt-image-2.
 * - Production reuses existing generated cover PNGs when local already generated them.
 *
 * Examples:
 *   node backend/scripts/upload-all-remaining-novels.mjs --mode both
 *   node backend/scripts/upload-all-remaining-novels.mjs --mode local --max-batches 1
 *   node backend/scripts/upload-all-remaining-novels.mjs --mode production --batch-size 5
 */
import fs from 'node:fs/promises';
import fssync from 'node:fs';
import path from 'node:path';
import { spawn } from 'node:child_process';
import { createRequire } from 'node:module';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, '..', '..');
const require = createRequire(import.meta.url);
const mysql = require(path.join(repoRoot, 'backend', 'node_modules', 'mysql2', 'promise'));
const dotenv = require(path.join(repoRoot, 'backend', 'node_modules', 'dotenv'));

dotenv.config({ path: path.join(repoRoot, 'backend', '.env') });

const DEFAULT_SOURCE = path.join(repoRoot, 'data', '全部完结短篇小说合集');
const DEFAULT_UPLOADER = path.join(
  process.env.CODEX_HOME || 'C:\\Users\\Administrator\\.codex',
  'skills',
  'xsread-novel-uploader',
  'scripts',
  'run_publish_smoke.mjs'
);
const DEFAULT_STATE_FILE = path.join(repoRoot, '.qa-test-output', 'upload-all-remaining-novels.state.json');

function parseArgs(argv) {
  const args = {
    mode: 'both',
    source: DEFAULT_SOURCE,
    uploader: DEFAULT_UPLOADER,
    batchSize: 5,
    concurrency: 5,
    coverTimeoutMs: 600000,
    maxBatches: 999,
    localUserBaseUrl: 'http://127.0.0.1:8005',
    productionUserBaseUrl: process.env.XSREAD_USER_BASE_URL || 'https://xs.momofx.cn',
    productionAdminBaseUrl: process.env.XSREAD_ADMIN_BASE_URL || 'https://admin.xs.momofx.cn',
    productionAdminToken: process.env.XSREAD_ADMIN_TOKEN || '',
    stateFile: DEFAULT_STATE_FILE,
    productionBatchDelayMs: 60000,
    productionRetryDelayMs: 15 * 60 * 1000,
    maxBatchRetries: 2,
    dryRun: false,
  };

  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index];
    const next = () => argv[++index];
    if (arg === '--dry-run') args.dryRun = true;
    else if (arg === '--mode') args.mode = next();
    else if (arg === '--source') args.source = path.resolve(next());
    else if (arg === '--uploader') args.uploader = path.resolve(next());
    else if (arg === '--batch-size') args.batchSize = Number(next());
    else if (arg === '--concurrency') args.concurrency = Number(next());
    else if (arg === '--cover-timeout-ms') args.coverTimeoutMs = Number(next());
    else if (arg === '--max-batches') args.maxBatches = Number(next());
    else if (arg === '--local-user-base-url') args.localUserBaseUrl = stripTrailingSlash(next());
    else if (arg === '--production-user-base-url') args.productionUserBaseUrl = stripTrailingSlash(next());
    else if (arg === '--production-admin-base-url') args.productionAdminBaseUrl = stripTrailingSlash(next());
    else if (arg === '--production-admin-token') args.productionAdminToken = next();
    else if (arg === '--production-batch-delay-ms') args.productionBatchDelayMs = Number(next());
    else if (arg === '--production-retry-delay-ms') args.productionRetryDelayMs = Number(next());
    else if (arg === '--max-batch-retries') args.maxBatchRetries = Number(next());
    else if (arg === '--state-file') args.stateFile = path.resolve(next());
    else if (arg.startsWith('--')) throw new Error(`Unknown argument: ${arg}`);
  }

  args.mode = String(args.mode || 'both').toLowerCase();
  if (!['both', 'local', 'production'].includes(args.mode)) {
    throw new Error('--mode must be one of: both, local, production');
  }
  args.batchSize = Math.min(5, Math.max(1, Number(args.batchSize || 5)));
  args.concurrency = Math.min(5, Math.max(1, Number(args.concurrency || args.batchSize)));
  args.coverTimeoutMs = Math.max(60000, Number(args.coverTimeoutMs || 600000));
  args.maxBatches = Math.max(1, Number(args.maxBatches || 999));
  args.productionBatchDelayMs = Math.max(0, Number(args.productionBatchDelayMs || 0));
  args.productionRetryDelayMs = Math.max(1000, Number(args.productionRetryDelayMs || 900000));
  args.maxBatchRetries = Math.max(0, Number(args.maxBatchRetries || 0));

  return args;
}

async function readJsonResponse(response, context) {
  const text = await response.text();
  try {
    return JSON.parse(text);
  } catch {
    throw new Error(`${context} returned non-json ${response.status}: ${text.slice(0, 160)}`);
  }
}

function stripTrailingSlash(value) {
  return String(value || '').replace(/\/+$/, '');
}

function stripBookMarks(title) {
  return String(title || '').replace(/^《/, '').replace(/》$/, '').trim();
}

function normalizeTitle(title) {
  return stripBookMarks(title)
    .normalize('NFKC')
    .replace(/[“”"'‘’]/g, '')
    .replace(/[\s　]+/g, ' ')
    .trim();
}

function nowIso() {
  return new Date().toISOString();
}

function log(event, data = {}) {
  console.log(JSON.stringify({ ts: nowIso(), event, ...data }, null, 2));
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function writeState(args, patch) {
  await fs.mkdir(path.dirname(args.stateFile), { recursive: true });
  let state = {};
  try {
    state = JSON.parse(await fs.readFile(args.stateFile, 'utf8'));
  } catch {
    state = {};
  }
  const next = { ...state, ...patch, updatedAt: nowIso() };
  await fs.writeFile(args.stateFile, `${JSON.stringify(next, null, 2)}\n`, 'utf8');
}

async function sourceTitles(args) {
  const entries = await fs.readdir(args.source, { withFileTypes: true });
  return entries
    .filter((entry) => (entry.isFile() && /\.txt$/i.test(entry.name)) || entry.isDirectory())
    .map((entry) => stripBookMarks(path.basename(entry.name, path.extname(entry.name))))
    .sort((a, b) => normalizeTitle(a).localeCompare(normalizeTitle(b), 'zh-Hans-CN'));
}

async function localTitles() {
  const database = process.env.DB_DATABASE || process.env.DB_NAME;
  if (!process.env.DB_HOST || !process.env.DB_USER || !database) {
    throw new Error('Missing DB_HOST, DB_USER, or DB_DATABASE/DB_NAME in backend/.env');
  }

  const db = await mysql.createConnection({
    host: process.env.DB_HOST,
    port: Number(process.env.DB_PORT || 3306),
    user: process.env.DB_USER,
    password: process.env.DB_PASSWORD || '',
    database,
    charset: 'utf8mb4',
  });

  try {
    const [rows] = await db.query('SELECT title FROM novels ORDER BY id');
    return rows.map((row) => row.title);
  } finally {
    await db.end();
  }
}

async function productionToken(args) {
  if (!args.productionAdminBaseUrl) throw new Error('Missing production admin base URL');
  if (args.productionAdminToken) return args.productionAdminToken;
  if (!process.env.XSREAD_ADMIN_USERNAME || !process.env.XSREAD_ADMIN_PASSWORD) {
    throw new Error('Missing XSREAD_ADMIN_TOKEN or XSREAD_ADMIN_USERNAME/XSREAD_ADMIN_PASSWORD in backend/.env');
  }

  for (let attempt = 0; attempt <= args.maxBatchRetries; attempt += 1) {
    const response = await fetch(`${args.productionAdminBaseUrl}/api/admin/login`, {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({
        username: process.env.XSREAD_ADMIN_USERNAME,
        password: process.env.XSREAD_ADMIN_PASSWORD,
      }),
    });
    let json;
    try {
      json = await readJsonResponse(response, 'Production admin login');
    } catch (error) {
      if (response.status === 429 && attempt < args.maxBatchRetries) {
        log('login_retry_wait', {
          target: 'production',
          attempt: attempt + 1,
          delayMs: args.productionRetryDelayMs,
          reason: error.message,
        });
        await sleep(args.productionRetryDelayMs);
        continue;
      }
      throw error;
    }
    const token = json.data?.accessToken;
    if (response.ok && token) {
      args.productionAdminToken = token;
      return token;
    }
    if (response.status !== 429 || attempt >= args.maxBatchRetries) {
      throw new Error(`Production admin login failed: ${json.message || response.status}`);
    }
    log('login_retry_wait', {
      target: 'production',
      attempt: attempt + 1,
      delayMs: args.productionRetryDelayMs,
    });
    await sleep(args.productionRetryDelayMs);
  }
  throw new Error('Production admin login failed after retries');
}

async function productionTitles(args) {
  const token = await productionToken(args);
  const all = [];

  for (let page = 1; ; page += 1) {
    const response = await fetch(`${args.productionAdminBaseUrl}/api/admin/novels?page=${page}&pageSize=200`, {
      headers: { authorization: `Bearer ${token}` },
    });
    const json = await readJsonResponse(response, 'Production novel list');
    if (!response.ok || json.code >= 400) {
      throw new Error(`Production novel list failed: ${json.message || response.status}`);
    }
    all.push(...(json.data?.list || []));
    if (page >= Number(json.data?.totalPages || 1)) break;
  }

  return all.map((row) => row.title);
}

async function missingTitles(args, target) {
  const source = await sourceTitles(args);
  const existing = target === 'local' ? await localTitles() : await productionTitles(args);
  const existingKeys = new Set(existing.map(normalizeTitle));
  return source.filter((title) => !existingKeys.has(normalizeTitle(title)));
}

function runUpload(args, target, titles) {
  return new Promise((resolve) => {
    const concurrency = target === 'production' ? 1 : Math.min(args.concurrency, titles.length);
    const commandArgs = [
      args.uploader,
      '--repo', repoRoot,
      '--source', args.source,
      '--titles', titles.join('|'),
      '--target', target,
      '--concurrency', String(concurrency),
      '--cover-timeout-ms', String(args.coverTimeoutMs),
    ];

    if (target === 'local') {
      commandArgs.push('--user-base-url', args.localUserBaseUrl);
    } else {
      commandArgs.push(
        '--confirm-production',
        '--user-base-url', args.productionUserBaseUrl,
        '--admin-base-url', args.productionAdminBaseUrl
      );
      if (args.productionAdminToken) {
        commandArgs.push('--admin-token', args.productionAdminToken);
      }
    }

    const child = spawn('node', commandArgs, {
      cwd: repoRoot,
      env: process.env,
      windowsHide: true,
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    child.stdout.on('data', (chunk) => process.stdout.write(chunk));
    child.stderr.on('data', (chunk) => process.stderr.write(chunk));
    child.on('close', (code) => resolve(Number(code || 0)));
  });
}

async function runUploadWithRetries(args, target, titles) {
  let attempt = 0;
  while (attempt <= args.maxBatchRetries) {
    const code = await runUpload(args, target, titles);
    if (code === 0) return 0;
    if (target !== 'production' || attempt >= args.maxBatchRetries) return code;
    attempt += 1;
    log('batch_retry_wait', {
      target,
      code,
      titles,
      attempt,
      delayMs: args.productionRetryDelayMs,
    });
    await sleep(args.productionRetryDelayMs);
  }
  return 1;
}

async function runTarget(args, target) {
  let batchesDone = 0;

  while (batchesDone < args.maxBatches) {
    const missing = await missingTitles(args, target);
    const nextBatch = missing.slice(0, args.batchSize);
    log('scan', {
      target,
      missingCount: missing.length,
      nextBatch,
    });
    await writeState(args, {
      status: 'running',
      currentTarget: target,
      missingCount: missing.length,
      nextBatch,
    });

    if (missing.length === 0) {
      log('target_complete', { target });
      return true;
    }

    if (args.dryRun) {
      log('dry_run_stop', { target });
      return true;
    }

    log('batch_start', { target, titles: nextBatch });
    const code = await runUploadWithRetries(args, target, nextBatch);
    if (code !== 0) {
      log('batch_failed', { target, code, titles: nextBatch });
      await writeState(args, {
        status: 'failed',
        failedTarget: target,
        failedBatch: nextBatch,
        exitCode: code,
      });
      return false;
    }
    log('batch_success', { target, titles: nextBatch });
    batchesDone += 1;
    if (target === 'production' && args.productionBatchDelayMs > 0) {
      log('batch_delay', { target, delayMs: args.productionBatchDelayMs });
      await sleep(args.productionBatchDelayMs);
    }
  }

  log('max_batches_reached', { target, maxBatches: args.maxBatches });
  return true;
}

async function runBackfill(target) {
  const backfill = path.join(repoRoot, 'backend', 'scripts', 'backfill-novel-initial-stats.js');
  if (!fssync.existsSync(backfill)) return;
  const commandArgs = [backfill, '--target', target];
  if (target === 'production') commandArgs.push('--confirm-production');

  await new Promise((resolve) => {
    const child = spawn('node', commandArgs, {
      cwd: repoRoot,
      env: process.env,
      windowsHide: true,
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    child.stdout.on('data', (chunk) => process.stdout.write(chunk));
    child.stderr.on('data', (chunk) => process.stderr.write(chunk));
    child.on('close', () => resolve());
  });
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  log('start', {
    mode: args.mode,
    source: args.source,
    batchSize: args.batchSize,
    concurrency: args.concurrency,
    coverTimeoutMs: args.coverTimeoutMs,
    dryRun: args.dryRun,
  });
  await writeState(args, { status: 'running', startedAt: nowIso(), mode: args.mode });

  if (args.mode === 'both' || args.mode === 'local') {
    const ok = await runTarget(args, 'local');
    if (!ok) process.exit(1);
    if (!args.dryRun) await runBackfill('local');
  }

  if (args.mode === 'both' || args.mode === 'production') {
    const ok = await runTarget(args, 'production');
    if (!ok) process.exit(1);
    if (!args.dryRun) await runBackfill('production');
  }

  const localMissing = await missingTitles(args, 'local');
  const productionMissing = await missingTitles(args, 'production');
  const finalState = {
    status: localMissing.length === 0 && productionMissing.length === 0 ? 'complete' : 'partial',
    localMissingCount: localMissing.length,
    productionMissingCount: productionMissing.length,
    finishedAt: nowIso(),
  };
  log('finish', finalState);
  await writeState(args, finalState);
}

main().catch(async (error) => {
  console.error(error.stack || error.message);
  try {
    await writeState(parseArgs(process.argv.slice(2)), {
      status: 'failed',
      error: error.message,
    });
  } catch {
    // Ignore state write errors during fatal handling.
  }
  process.exit(1);
});
